mapper.select:
select id, title, content, type, business_id, read_status, create_time from message where user_id = #{userId} and is_deleted = 0
and read_status = #{readStatus}
order by id desc

mapper.update:
update message
set read_status = 1,
    update_time = now()
where id = #{messageId}
  and user_id = #{userId}
  and is_deleted = 0
